/* ==================================================
   KUBEQUEST — Question Bank (EN + FR)
   ================================================== */

function getQuestions(diff) {
  return QUESTIONS[currentLang][diff];
}

const QUESTIONS = {
  en: {
  recruit: [
    {type:'qcm',category:'Architecture',question:"What is Kubernetes?",hint:'Think about managing containers at scale.',options:["A Linux operating system","A container orchestrator","A programming language","A cloud provider"],answer:1,explain:"Kubernetes (K8s) is an open-source container orchestration system. It automates the deployment, scaling, and management of containerized applications."},
    {type:'tf',category:'Concepts',question:"A Pod can contain multiple containers that share the same network.",answer:true,explain:"True! Containers within the same Pod share the same IP address and can communicate via localhost. It's the basic unit of deployment in K8s."},
    {type:'qcm',category:'Architecture',question:"Which control plane component stores the entire cluster state?",options:['kube-scheduler','kube-apiserver','etcd','kubelet'],answer:2,explain:"etcd is a distributed key-value database. It's the absolute source of truth for the cluster. If etcd is lost, the cluster is lost.",code:"# Back up etcd\netcdctl snapshot save backup.db"},
    {type:'qcm',category:'Workloads',question:"What is the main difference between a Pod and a Deployment?",options:["A Pod is faster","A Deployment ensures high availability and rolling updates","A Pod can auto-scale","There is no difference"],answer:1,explain:"A Deployment manages ReplicaSets that keep N Pods alive. It enables rolling updates, rollbacks, and guarantees the right number of Pods are always running."},
    {type:'tf',category:'Networking',question:"A ClusterIP Service is accessible from outside the cluster.",answer:false,explain:"False! ClusterIP is only accessible from within the cluster. To expose externally, use NodePort, LoadBalancer, or an Ingress."},
    {type:'qcm',category:'Architecture',question:"Which component runs on every worker node and starts containers?",options:['kube-proxy','kubelet','kube-scheduler','etcd'],answer:1,explain:"kubelet is the agent that runs on every worker node. It watches the API Server for Pods assigned to its node and starts them via the container runtime."},
    {type:'qcm',category:'Networking',question:"What is a Service in Kubernetes?",hint:'It provides a stable address to reach ephemeral Pods.',options:["A special container","A network abstraction with a stable IP to access Pods","A configuration file","A worker node"],answer:1,explain:"A Service exposes a set of Pods via a stable IP and DNS name. Pods have ephemeral IPs that change; the Service solves this problem."},
    {type:'tf',category:'Workloads',question:"kubectl is the official CLI tool for interacting with Kubernetes.",answer:true,explain:"True! kubectl is the main K8s CLI. It communicates with the API Server for all operations: create, list, delete resources.",code:"kubectl get pods\nkubectl describe pod <name>\nkubectl apply -f file.yaml"},
    {type:'qcm',category:'Config',question:"Which K8s resource stores NON-sensitive configuration data?",options:['Secret','ConfigMap','PersistentVolume','ServiceAccount'],answer:1,explain:"ConfigMap stores configuration data in plain text: config files, environment variables. For sensitive data (passwords, tokens), use Secrets."},
    {type:'qcm',category:'Architecture',question:"What is the role of kube-scheduler?",options:["It starts containers on nodes","It decides which node an unassigned Pod should run on","It manages network rules","It stores the cluster state"],answer:1,explain:"The scheduler watches for unassigned Pods and picks the best node to place them on, based on available resources, affinity constraints, taints..."},
    {type:'tf',category:'Workloads',question:"A DaemonSet ensures that a Pod runs on EVERY node in the cluster.",answer:true,explain:"True! DaemonSets are perfect for monitoring agents (Prometheus node-exporter), log collectors (Fluentd), or network plugins (CNI) that must run everywhere."},
    {type:'qcm',category:'Concepts',question:'K8s is called "declarative". What does that mean?',hint:'You describe WHAT you want, not HOW to get there.',options:["You write code for every operation","You describe the desired state and K8s converges toward it","You must start each container manually","You must configure everything via CLI"],answer:1,explain:"The declarative model: you describe the desired end state in a YAML file, K8s does all the work to achieve it. It continuously reconciles the actual state with the desired state."},
    {type:'qcm',category:'Networking',question:"Which Service type automatically creates a cloud load balancer?",options:['ClusterIP','NodePort','LoadBalancer','ExternalName'],answer:2,explain:"The LoadBalancer type automatically provisions a load balancer from the cloud provider (AWS ELB, GCP LB...) and assigns it a public IP."},
    {type:'tf',category:'Architecture',question:"The control plane can also run application Pods in production.",answer:false,explain:"False! In production, the control plane is reserved for system components (API Server, etcd, scheduler...). Application Pods run on worker nodes."},
    {type:'qcm',category:'Workloads',question:"Which K8s object is ideal for a database requiring stable storage?",options:['Deployment','ReplicaSet','StatefulSet','DaemonSet'],answer:2,explain:"StatefulSet gives each Pod a stable identity (pod-0, pod-1...) and a dedicated PVC that persists even if the Pod restarts. Ideal for MySQL, PostgreSQL, Kafka..."},
    {type:'qcm',category:'Concepts',question:"What happens if a Pod crashes in a ReplicaSet with 3 replicas?",options:["The service stops","K8s automatically creates a new Pod","You must restart it manually","The node is rebooted"],answer:1,explain:"This is K8s self-healing! The ReplicaSet controller detects the Pod count dropped to 2 and immediately creates a new Pod to restore it to 3."},
    {type:'qcm',category:'Networking',question:"What is an Ingress?",options:["A type of Pod","An HTTP/HTTPS router that directs traffic to Services based on URL","A type of volume","A special worker node"],answer:1,explain:"Ingress routes HTTP/HTTPS traffic (layer 7) to different Services based on host or path. E.g.: /api → backend-service, /app → frontend-service."},
    {type:'tf',category:'Config',question:"Kubernetes Secrets are encrypted by default in etcd.",answer:false,explain:"False! By default, Secrets are base64-encoded, not encrypted. base64 ≠ encryption. You must explicitly enable etcd encryption at rest."},
    {type:'qcm',category:'Commands',question:"Which command displays the logs of a Pod?",options:['kubectl describe pod <name>','kubectl logs <pod-name>','kubectl get pod <name>','kubectl inspect <pod-name>'],answer:1,explain:"kubectl logs <pod-name> displays the container's stdout/stderr logs. Use --previous for a crashed container, -f to follow in real time.",code:"kubectl logs my-pod\nkubectl logs my-pod --previous\nkubectl logs my-pod -f"},
    {type:'qcm',category:'Architecture',question:"Which component implements network rules for Services on each node?",options:['kubelet','kube-dns','kube-proxy','containerd'],answer:2,explain:"kube-proxy programs iptables/ipvs rules on each node so that calls to a ClusterIP Service are routed to the correct Pods."},
  ],
  engineer: [
    {type:'qcm',category:'Resources',question:'What is the difference between "requests" and "limits" on a container?',hint:"One is a guarantee, the other is a ceiling.",options:['Requests = max CPU, limits = min CPU','Requests = resources reserved by the scheduler, limits = hard ceiling','Requests = RAM, limits = CPU','They are synonyms'],answer:1,explain:"Requests = what the scheduler reserves on the node (guaranteed). Limits = absolute ceiling. If CPU exceeds the limit → throttling. If RAM exceeds → OOMKilled.",code:'resources:\n  requests:\n    cpu: "250m"\n    memory: "64Mi"\n  limits:\n    cpu: "500m"\n    memory: "128Mi"'},
    {type:'tf',category:'Networking',question:'CoreDNS automatically resolves "my-service" to its ClusterIP from any Pod in the same namespace.',answer:true,explain:"CoreDNS creates DNS entries for every Service. From the same namespace, the short name is enough. Full format: my-service.my-ns.svc.cluster.local"},
    {type:'qcm',category:'Debugging',question:"A Pod is in CrashLoopBackOff state. What is your first command?",options:['kubectl delete pod <name>','kubectl describe pod <name> AND kubectl logs <name> --previous','kubectl restart pod <name>','kubectl edit pod <name>'],answer:1,explain:"describe gives you the events (OOMKilled? probe failed?), logs --previous gives the container logs before the crash. These two commands together provide 90% of the information.",code:"kubectl describe pod <name>\nkubectl logs <name> --previous\nkubectl get events --sort-by=lastTimestamp"},
    {type:'qcm',category:'Workloads',question:"Which deployment strategy avoids all downtime?",options:['Recreate','RollingUpdate','BlueGreen','Immediate'],answer:1,explain:"RollingUpdate replaces Pods progressively (maxSurge/maxUnavailable parameters). Recreate deletes all Pods then recreates them → guaranteed downtime.",code:"strategy:\n  type: RollingUpdate\n  rollingUpdate:\n    maxSurge: 1\n    maxUnavailable: 0"},
    {type:'tf',category:'Probes',question:"If the liveness probe fails, Kubernetes removes the Pod from Service endpoints but does not restart it.",answer:false,explain:"False! A liveness probe failure causes K8s to restart the container. It's the readiness probe that removes the Pod from endpoints without restarting."},
    {type:'qcm',category:'Config',question:"How do you mount a ConfigMap so changes propagate automatically without restart?",options:["Via envFrom (env variables)",'Via valueFrom','Via a volume',"It's not possible"],answer:2,explain:"Mounted as a volume, a ConfigMap updates automatically in the Pod (~1 min delay). Via envFrom, the Pod must restart to see changes."},
    {type:'qcm',category:'Commands',question:"How do you rollback to the previous version of a Deployment?",options:['kubectl reset deploy/my-app','kubectl rollout undo deploy/my-app','kubectl revert deploy/my-app','kubectl restore deploy/my-app'],answer:1,explain:"kubectl rollout undo reverts to the previous ReplicaSet. Use --to-revision=N to choose a specific revision.",code:"kubectl rollout undo deploy/my-app\nkubectl rollout history deploy/my-app\nkubectl rollout undo deploy/my-app --to-revision=2"},
    {type:'order',category:'Workloads',question:"Put in order the components traversed during kubectl apply:",items:['kubectl CLI','kube-apiserver','Admission controllers','etcd','Controller Manager creates the Pods'],answer:[0,1,2,3,4],explain:"kubectl → API Server (auth + RBAC) → Admission controllers (validation/mutation) → etcd (persistence) → Controller Manager reacts and creates resources."},
    {type:'qcm',category:'Scheduling',question:"What QoS class does a Pod get if requests == limits on all its containers?",options:['BestEffort','Burstable','Guaranteed','Premium'],answer:2,explain:"Guaranteed: requests == limits on all containers → highest priority, evicted last under memory pressure. This is the recommended class for critical services."},
    {type:'tf',category:'Networking',question:"An Ingress Controller is included by default in every Kubernetes installation.",answer:false,explain:"False! The Ingress object alone does nothing. You must install an Ingress Controller (nginx, traefik, HAProxy...) separately for Ingress rules to take effect."},
    {type:'qcm',category:'Storage',question:"What is the difference between a PersistentVolume (PV) and a PersistentVolumeClaim (PVC)?",options:['PV = for databases, PVC = for files','PV = storage provisioned in the cluster, PVC = storage request made by a Pod','PVC is created by the admin, PV by the developer','They are synonyms'],answer:1,explain:'PV = the actual storage (NFS, EBS, local disk...). PVC = a Pod\'s request ("I need 10Gi in ReadWriteOnce"). K8s performs the PVC→PV binding automatically.'},
    {type:'qcm',category:'Debugging',question:'A Pod is stuck in "Pending" state. What is the most likely cause?',options:["The container crashes on startup","No node has enough resources for the scheduler","The liveness probe fails","The Secret doesn't exist"],answer:1,explain:"Pending = the scheduler couldn't place the Pod. Causes: insufficient resources, overly restrictive node affinity, taints without tolerations. kubectl describe pod → Events."},
    {type:'qcm',category:'Security',question:"What does an RBAC Role define in Kubernetes?",options:["A cluster user","A set of permissions on resources within ONE namespace","A set of cluster-wide permissions","A group of nodes"],answer:1,explain:"Role = permissions within a namespace. ClusterRole = cluster-wide permissions. RoleBinding attaches a Role to a user or ServiceAccount within a namespace.",code:'kind: Role\napiVersion: rbac.authorization.k8s.io/v1\nrules:\n- apiGroups: [""]\n  resources: ["pods"]\n  verbs: ["get","list","watch"]'},
    {type:'tf',category:'Workloads',question:"An Init Container must complete successfully (exit 0) before the main container starts.",answer:true,explain:"True! Init Containers run sequentially before the main containers. If an Init Container fails, K8s restarts it according to the restartPolicy."},
    {type:'qcm',category:'Scheduling',question:"What is pod anti-affinity used for?",hint:'Think about high availability.',options:["Preventing a Pod from starting","Forcing identical Pods to run on different nodes","Limiting CPU consumption","Assigning a Pod to a specific node"],answer:1,explain:"Pod anti-affinity prevents co-locating similar Pods. E.g.: 3 replicas of a service spread across 3 different nodes → resilience to node failures."},
    {type:'qcm',category:'Commands',question:"Which command opens a shell in a running container?",options:['kubectl run <pod> --sh','kubectl attach <pod>','kubectl exec -it <pod> -- /bin/sh','kubectl shell <pod>'],answer:2,explain:"kubectl exec -it <pod> -- /bin/sh opens an interactive terminal in the container. Essential for live debugging: checking files, env variables, network connectivity.",code:"kubectl exec -it my-pod -- /bin/sh\nkubectl exec -it my-pod -c my-container -- bash"},
    {type:'tf',category:'Networking',question:"kube-proxy actually proxies network traffic in user space.",answer:false,explain:"False! kube-proxy programs iptables (or ipvs) rules in the kernel. Traffic doesn't pass through kube-proxy itself — the kernel routes it directly."},
    {type:'qcm',category:'Workloads',question:"Which resource automatically scales the number of replicas based on CPU usage?",options:['VerticalPodAutoscaler','HorizontalPodAutoscaler','ClusterAutoscaler','ReplicaController'],answer:1,explain:"HPA (HorizontalPodAutoscaler) adjusts the number of Pods based on metrics (CPU, RAM, custom). Requires Metrics Server and CPU requests to be defined.",code:"kubectl autoscale deploy my-app \\\n  --min=2 --max=10 --cpu-percent=70"},
    {type:'qcm',category:'Debugging',question:'What does a Pod in "OOMKilled" state indicate?',options:["The Pod exceeded its CPU limit","The Pod exceeded its memory limit","The liveness probe failed","The node went down"],answer:1,explain:"OOMKilled = Out Of Memory Killed. The container exceeded its memory limit and the kernel killed it. Solution: increase the memory limit, or debug the memory leak."},
    {type:'qcm',category:'Architecture',question:"What mechanism do K8s components use to be notified of changes in real time?",options:["Polling every second","HTTP long-polling","Watch on the API Server","Webhook push"],answer:2,explain:"All components (kubelet, controller-manager...) use the API Server's watch mechanism: a long-lived connection that streams events as soon as an object changes."},
  ],
  architect: [
    {type:'qcm',category:'Security',question:"A Pod needs to read AWS secrets from Vault. What is the proper K8s-native approach?",hint:'Think about the principle of least privilege.',options:["Put credentials in a ConfigMap","Use a ServiceAccount + IRSA/Workload Identity + External Secrets Operator","Hard-code credentials in the image","Pass credentials as container arguments"],answer:1,explain:"Best practice: ServiceAccount with cloud annotation (IRSA on AWS, Workload Identity on GCP) + External Secrets Operator that syncs Vault/cloud secrets to K8s Secrets."},
    {type:'tf',category:'Networking',question:'A "deny-all" ingress NetworkPolicy on a namespace also blocks traffic between Pods in the same namespace.',answer:true,explain:"True! An ingress NetworkPolicy without podSelector or namespaceSelector blocks all incoming traffic, including intra-namespace. You must explicitly allow Pods to communicate."},
    {type:'qcm',category:'Scheduling',question:"What is the difference between a Taint and a Toleration?",options:["Taint = on the Pod, Toleration = on the Node","Taint = on the Node (repels), Toleration = on the Pod (allows tolerating)","They are synonyms","Taint = resource, Toleration = constraint"],answer:1,explain:'Taint on a Node: "don\'t schedule Pods here unless they tolerate this taint". Toleration on a Pod: "I accept running on nodes with this taint". E.g.: dedicated GPU nodes.',code:"# Taint a GPU node\nkubectl taint nodes gpu-node gpu=true:NoSchedule\n\n# Toleration in the Pod spec\ntolerations:\n- key: \"gpu\"\n  value: \"true\"\n  effect: \"NoSchedule\""},
    {type:'qcm',category:'Security',question:"What is a Mutating Admission Webhook?",hint:'It intervenes BEFORE persistence in etcd.',options:["A webhook that deletes non-compliant resources","A webhook that modifies K8s objects before they are persisted in etcd","A monitoring tool for API Server access","An etcd backup mechanism"],answer:1,explain:"MutatingAdmissionWebhook intercepts API requests and can modify objects before persistence. E.g.: automatic Istio sidecar injection, label addition, PodSecurityContext injection."},
    {type:'order',category:'Debugging',question:"Put in order the diagnosis of an unreachable service:",items:["Check the Service Endpoints","Test DNS resolution","Check Pod labels and Service selector","Check NetworkPolicies","Test with kubectl port-forward"],answer:[2,1,0,3,4],explain:"1) Pod labels == Service selector? 2) Does DNS resolve? 3) Do Endpoints exist? 4) Is a NetworkPolicy blocking? 5) port-forward to isolate the network issue."},
    {type:'qcm',category:'Architecture',question:"In an HA cluster, how many etcd replicas are needed to tolerate 1 failure?",options:['2','3','4','5'],answer:1,explain:"etcd uses Raft consensus. To tolerate N failures, you need 2N+1 members. For 1 failure → 3 members (quorum = 2). For 2 failures → 5 members."},
    {type:'tf',category:'Workloads',question:"A PodDisruptionBudget (PDB) prevents K8s from evicting too many Pods simultaneously during maintenance.",answer:true,explain:"True! PDB defines minAvailable or maxUnavailable. During a node drain, K8s respects the PDB and waits for Pods to be recreated before evicting more.",code:"spec:\n  minAvailable: 2  # or maxUnavailable: 1\n  selector:\n    matchLabels:\n      app: my-critical-service"},
    {type:'qcm',category:'Networking',question:"What is the CNI (Container Network Interface) in Kubernetes?",options:["The cluster's internal DNS","A network plugin standard that configures connectivity between Pods","The protocol between kubelet and etcd","The K8s authentication system"],answer:1,explain:"CNI is the network plugin standard. Examples: Calico (advanced NetworkPolicies), Cilium (eBPF, observability), Flannel (simple). Kubelet calls the CNI to configure Pod network interfaces."},
    {type:'qcm',category:'Security',question:"What is the difference between AuthN and AuthZ in K8s?",options:["They are synonyms","AuthN = verify identity (who are you?), AuthZ = verify permissions (what can you do?)","AuthN = for Pods, AuthZ = for users","AuthN is handled by RBAC, AuthZ by certificates"],answer:1,explain:"AuthN (Authentication): who are you? Via TLS certificates, tokens, OIDC. AuthZ (Authorization): what are you allowed to do? Via RBAC. Both steps occur in the API Server before admission."},
    {type:'tf',category:'Architecture',question:"Kubernetes can self-heal a cluster whose API Server is unavailable by using kubelet directly.",answer:false,explain:'False! Without the API Server, the cluster is "frozen". Kubelets continue running existing Pods, but no new scheduling decisions or reconciliation is possible.'},
    {type:'qcm',category:'Performance',question:"What is the Vertical Pod Autoscaler (VPA)?",options:["It adds nodes to the cluster","It automatically adjusts CPU and RAM requests/limits for Pods","It adjusts the number of Pods","It migrates Pods to more powerful nodes"],answer:1,explain:"VPA analyzes actual resource usage and recommends (or applies) optimal requests/limits. Incompatible with HPA on the same CPU/RAM metric."},
    {type:'qcm',category:'Architecture',question:"What is a Kubernetes Operator?",hint:'Think of the Controller Manager, but for your own applications.',options:["A human cluster administrator","A custom controller that encodes operational knowledge of an application into K8s","A privileged Pod type","A kubelet plugin"],answer:1,explain:"An Operator extends K8s with CRDs + custom controllers. It automates complex operational tasks (DB backup, failover, application scaling...). E.g.: Prometheus Operator, Postgres Operator."},
    {type:'tf',category:'Security',question:"ServiceAccount tokens mounted by default in Pods never expire.",answer:false,explain:"False since K8s 1.21+! ServiceAccount tokens mounted automatically (via TokenRequest API) have a limited lifetime (default 1h). Kubelet renews them automatically."},
    {type:'qcm',category:'Debugging',question:"A Deployment has been stuck in Rolling Update for 10 minutes. Which command gives the status?",options:['kubectl get deploy my-app','kubectl describe deploy my-app','kubectl rollout status deploy/my-app','kubectl logs deploy/my-app'],answer:2,explain:"kubectl rollout status blocks and displays real-time progress. If stuck, it's often a readiness probe failing on the new Pods.",code:"kubectl rollout status deploy/my-app\nkubectl rollout history deploy/my-app\n# Cancel if stuck:\nkubectl rollout undo deploy/my-app"},
    {type:'qcm',category:'Architecture',question:"What is a CRD (Custom Resource Definition)?",options:["A type of encrypted Secret","A way to extend the K8s API with your own resource types","A kubectl plugin","An advanced NetworkPolicy rule"],answer:1,explain:"CRD lets you define new K8s resource types (e.g.: MyApp, DatabaseCluster). Once created, kubectl recognizes them natively. Combined with an Operator, it's the foundation of the K8s ecosystem."},
    {type:'qcm',category:'Scheduling',question:'What is "Preemption" in K8s scheduling?',options:["The scheduler prioritizes recent Pods","The scheduler can evict low-priority Pods to place high-priority ones","A backup mechanism","Node autoscaling"],answer:1,explain:"With PriorityClasses, K8s can evict low-priority Pods (Preemption) to free up space for pending high-priority Pods. Configurable via PodPriorityClass.",code:"apiVersion: scheduling.k8s.io/v1\nkind: PriorityClass\nvalue: 1000000\npreemptionPolicy: PreemptLowerPriority"},
    {type:'tf',category:'Networking',question:"With Cilium in eBPF mode, kube-proxy can be completely replaced.",answer:true,explain:"True! Cilium in eBPF mode replaces kube-proxy and iptables rules with eBPF programs in the kernel, offering better performance and enhanced observability."},
    {type:'qcm',category:'Architecture',question:'What is the purpose of a "finalizer" on a K8s resource?',options:["Prevent actual deletion until cleanup logic has been executed","Encrypt the resource before storing in etcd","Log all modifications","Validate the YAML schema"],answer:0,explain:"A finalizer blocks the actual deletion of a resource until a controller removes it (after executing cleanup). E.g.: deleting a PVC forces K8s to wait for the volume to be released."},
    {type:'qcm',category:'Performance',question:'Node Affinity "preferredDuringSchedulingIgnoredDuringExecution" means:',options:["The Pod can only start on this node","The scheduler prefers this node but can choose another if needed","The affinity is applied even if the Pod is already running","The Pod is migrated if the node no longer satisfies the rule"],answer:1,explain:'"preferred" = soft constraint, the scheduler does its best. "required" = hard constraint, the Pod won\'t start if no node matches. "IgnoredDuringExecution" = no migration if the node changes.'},
    {type:'qcm',category:'Security',question:"What is Pod Security Admission (replacing PodSecurityPolicy since K8s 1.25)?",options:["A Pod encryption system","A controller that enforces security profiles (restricted/baseline/privileged) on Pods in a namespace","A type of NetworkPolicy","A multi-factor authentication mechanism"],answer:1,explain:"PSA enforces 3 profiles on namespaces via labels: privileged (no restrictions), baseline (prevents privilege escalation), restricted (strict best practices). Replaces the deprecated PodSecurityPolicies.",code:"# Label on the namespace\nkubectl label namespace my-ns \\\n  pod-security.kubernetes.io/enforce=restricted"},
    {type:'tf',category:'Architecture',question:'The kube-scheduler is a "pluggable" component that can be replaced or extended with a custom scheduler.',answer:true,explain:"True! K8s supports scheduling framework plugins and scheduler extenders. You can write a custom scheduler or use multiple scheduling profiles for different workloads."},
  ]
},
  fr: {
  recruit: [
    {type:'qcm',category:'Architecture',question:"Qu'est-ce que Kubernetes ?",hint:'Pensez à la gestion de containers à grande échelle.',options:["Un système d'exploitation Linux","Un orchestrateur de containers","Un langage de programmation","Un fournisseur cloud"],answer:1,explain:"Kubernetes (K8s) est un système open-source d'orchestration de containers. Il automatise le déploiement, la mise à l'échelle et la gestion des applications conteneurisées."},
    {type:'tf',category:'Concepts',question:"Un Pod peut contenir plusieurs containers qui partagent le même réseau.",answer:true,explain:"Vrai ! Les containers d'un même Pod partagent la même adresse IP et peuvent communiquer via localhost. C'est l'unité de base de déploiement dans K8s."},
    {type:'qcm',category:'Architecture',question:"Quel composant du control plane stocke l'intégralité de l'état du cluster ?",options:['kube-scheduler','kube-apiserver','etcd','kubelet'],answer:2,explain:"etcd est une base de données clé-valeur distribuée. C'est la source de vérité absolue du cluster. Si etcd est perdu, le cluster est perdu.",code:"# Sauvegarder etcd\netcdctl snapshot save backup.db"},
    {type:'qcm',category:'Workloads',question:"Quelle est la différence principale entre un Pod et un Deployment ?",options:["Un Pod est plus rapide","Un Deployment assure la haute disponibilité et les mises à jour progressives","Un Pod peut évoluer automatiquement","Il n'y a pas de différence"],answer:1,explain:"Un Deployment gère des ReplicaSets qui maintiennent N Pods en vie. Il permet les mises à jour progressives, les retours arrière, et garantit que le bon nombre de Pods tourne toujours."},
    {type:'tf',category:'Réseau',question:"Un Service ClusterIP est accessible depuis l'extérieur du cluster.",answer:false,explain:"Faux ! ClusterIP n'est accessible que depuis l'intérieur du cluster. Pour exposer vers l'extérieur, on utilise NodePort, LoadBalancer ou un Ingress."},
    {type:'qcm',category:'Architecture',question:"Quel composant tourne sur chaque worker node et démarre les containers ?",options:['kube-proxy','kubelet','kube-scheduler','etcd'],answer:1,explain:"kubelet est l'agent qui tourne sur chaque worker node. Il surveille l'API Server pour les Pods assignés à son node et les démarre via le container runtime."},
    {type:'qcm',category:'Réseau',question:"Qu'est-ce qu'un Service dans Kubernetes ?",hint:'Il fournit une adresse stable pour accéder à des Pods éphémères.',options:["Un container spécial","Une abstraction réseau avec IP stable pour accéder à des Pods","Un fichier de configuration","Un worker node"],answer:1,explain:"Un Service expose un ensemble de Pods via une IP stable et un nom DNS. Les Pods ont des IPs éphémères qui changent ; le Service résout ce problème."},
    {type:'tf',category:'Workloads',question:"kubectl est l'outil en ligne de commande officiel pour interagir avec Kubernetes.",answer:true,explain:"Vrai ! kubectl est le CLI principal de K8s. Il communique avec l'API Server pour toutes les opérations : créer, lister, supprimer des ressources.",code:"kubectl get pods\nkubectl describe pod <nom>\nkubectl apply -f fichier.yaml"},
    {type:'qcm',category:'Config',question:"Quelle ressource K8s stocke des données de configuration NON sensibles ?",options:['Secret','ConfigMap','PersistentVolume','ServiceAccount'],answer:1,explain:"ConfigMap stocke des données de configuration en clair : fichiers de config, variables d'environnement. Pour les données sensibles (mots de passe, tokens), on utilise Secret."},
    {type:'qcm',category:'Architecture',question:"Quel est le rôle du kube-scheduler ?",options:["Il démarre les containers sur les nodes","Il décide sur quel node un Pod non assigné doit tourner","Il gère les règles réseau","Il stocke l'état du cluster"],answer:1,explain:"Le scheduler observe les Pods sans node assigné et choisit le meilleur node pour les placer, selon les ressources disponibles, les contraintes d'affinité, les taints..."},
    {type:'tf',category:'Workloads',question:"Un DaemonSet garantit qu'un Pod tourne sur CHAQUE node du cluster.",answer:true,explain:"Vrai ! Le DaemonSet est parfait pour les agents de monitoring (Prometheus node-exporter), de logs (Fluentd), ou réseau (CNI) qui doivent tourner partout."},
    {type:'qcm',category:'Concepts',question:'K8s est dit "déclaratif". Qu\'est-ce que cela signifie ?',hint:'Tu décris CE QUE tu veux, pas COMMENT y arriver.',options:["Tu écris du code pour chaque opération","Tu décris l'état souhaité et K8s converge vers cet état","Tu dois démarrer chaque container manuellement","Tu dois tout configurer en ligne de commande"],answer:1,explain:"Le modèle déclaratif : tu décris l'état final souhaité dans un fichier YAML, K8s fait tout le travail pour l'atteindre. Il réconcilie en permanence l'état réel et l'état souhaité."},
    {type:'qcm',category:'Réseau',question:"Quel type de Service crée automatiquement un load balancer cloud ?",options:['ClusterIP','NodePort','LoadBalancer','ExternalName'],answer:2,explain:"Le type LoadBalancer provisionne automatiquement un load balancer chez le fournisseur cloud (AWS ELB, GCP LB...) et lui attribue une IP publique."},
    {type:'tf',category:'Architecture',question:"Le control plane peut aussi exécuter des Pods applicatifs en production.",answer:false,explain:"Faux ! En production, le control plane est réservé aux composants système (API Server, etcd, scheduler...). Les Pods applicatifs tournent sur les worker nodes."},
    {type:'qcm',category:'Workloads',question:"Quel objet K8s est idéal pour une base de données nécessitant un stockage stable ?",options:['Deployment','ReplicaSet','StatefulSet','DaemonSet'],answer:2,explain:"StatefulSet donne à chaque Pod une identité stable (pod-0, pod-1...) et un PVC dédié qui persiste même si le Pod redémarre. Idéal pour MySQL, PostgreSQL, Kafka..."},
    {type:'qcm',category:'Concepts',question:"Que se passe-t-il si un Pod crashe dans un ReplicaSet de 3 replicas ?",options:["Le service s'arrête","K8s crée un nouveau Pod automatiquement","Il faut le relancer manuellement","Le node est redémarré"],answer:1,explain:"C'est le self-healing de K8s ! Le controller du ReplicaSet détecte que le nombre de Pods est tombé à 2 et crée immédiatement un nouveau Pod pour revenir à 3."},
    {type:'qcm',category:'Réseau',question:"Qu'est-ce qu'un Ingress ?",options:["Un type de Pod","Un routeur HTTP/HTTPS qui redirige vers des Services selon l'URL","Un type de volume","Un worker node spécial"],answer:1,explain:"L'Ingress route le trafic HTTP/HTTPS (couche 7) vers différents Services selon le host ou le chemin. Ex. : /api → backend-service, /app → frontend-service."},
    {type:'tf',category:'Config',question:"Les Secrets Kubernetes sont chiffrés par défaut dans etcd.",answer:false,explain:"Faux ! Par défaut, les Secrets sont encodés en base64, pas chiffrés. base64 ≠ chiffrement. Il faut activer le chiffrement at-rest d'etcd explicitement."},
    {type:'qcm',category:'Commandes',question:"Quelle commande affiche les logs d'un Pod ?",options:['kubectl describe pod <nom>','kubectl logs <nom-du-pod>','kubectl get pod <nom>','kubectl inspect <nom-du-pod>'],answer:1,explain:"kubectl logs <nom-du-pod> affiche les logs stdout/stderr du container. Avec --previous pour le container crashé, -f pour suivre en temps réel.",code:"kubectl logs mon-pod\nkubectl logs mon-pod --previous\nkubectl logs mon-pod -f"},
    {type:'qcm',category:'Architecture',question:"Quel composant implémente les règles réseau pour les Services sur chaque node ?",options:['kubelet','kube-dns','kube-proxy','containerd'],answer:2,explain:"kube-proxy programme les règles iptables/ipvs sur chaque node pour que les appels vers un Service ClusterIP soient redirigés vers les bons Pods."},
  ],
  engineer: [
    {type:'qcm',category:'Ressources',question:'Quelle est la différence entre "requests" et "limits" sur un container ?',hint:"L'une est une garantie, l'autre est un plafond.",options:['Requests = max CPU, limits = min CPU','Requests = ressources réservées par le scheduler, limits = plafond non dépassable','Requests = RAM, limits = CPU','Ce sont des synonymes'],answer:1,explain:"Requests = ce que le scheduler réserve sur le node (garanti). Limits = plafond absolu. Si le CPU dépasse la limit → throttling. Si la RAM dépasse → OOMKilled.",code:'resources:\n  requests:\n    cpu: "250m"\n    memory: "64Mi"\n  limits:\n    cpu: "500m"\n    memory: "128Mi"'},
    {type:'tf',category:'Réseau',question:'CoreDNS résout automatiquement "mon-service" vers son ClusterIP depuis n\'importe quel Pod du même namespace.',answer:true,explain:"CoreDNS crée des entrées DNS pour chaque Service. Depuis le même namespace, le nom court suffit. Format complet : mon-service.mon-ns.svc.cluster.local"},
    {type:'qcm',category:'Débogage',question:"Un Pod est en état CrashLoopBackOff. Quelle est votre première commande ?",options:['kubectl delete pod <nom>','kubectl describe pod <nom> ET kubectl logs <nom> --previous','kubectl restart pod <nom>','kubectl edit pod <nom>'],answer:1,explain:"describe donne les événements (OOMKilled ? probe failed ?), logs --previous donne les logs du container avant le crash. Ces deux commandes ensemble fournissent 90 % des informations.",code:"kubectl describe pod <nom>\nkubectl logs <nom> --previous\nkubectl get events --sort-by=lastTimestamp"},
    {type:'qcm',category:'Workloads',question:"Quelle stratégie de déploiement évite tout downtime ?",options:['Recreate','RollingUpdate','BlueGreen','Immediate'],answer:1,explain:"RollingUpdate remplace les Pods progressivement (paramètres maxSurge/maxUnavailable). Recreate supprime tous les Pods puis les recrée → downtime garanti.",code:"strategy:\n  type: RollingUpdate\n  rollingUpdate:\n    maxSurge: 1\n    maxUnavailable: 0"},
    {type:'tf',category:'Probes',question:"Si la liveness probe échoue, Kubernetes retire le Pod des endpoints du Service mais ne le redémarre pas.",answer:false,explain:"Faux ! Un échec de la liveness probe entraîne le redémarrage du container par K8s. C'est la readiness probe qui retire le Pod des endpoints sans redémarrer."},
    {type:'qcm',category:'Config',question:"Comment monter un ConfigMap pour que les modifications se propagent automatiquement sans redémarrage ?",options:["Via envFrom (variables d'env)",'Via valueFrom','Via un volume',"Ce n'est pas possible"],answer:2,explain:"Monté en volume, un ConfigMap se met à jour automatiquement dans le Pod (~1 min de délai). Via envFrom, le Pod doit redémarrer pour voir les changements."},
    {type:'qcm',category:'Commandes',question:"Comment effectuer un retour arrière vers la version précédente d'un Deployment ?",options:['kubectl reset deploy/mon-app','kubectl rollout undo deploy/mon-app','kubectl revert deploy/mon-app','kubectl restore deploy/mon-app'],answer:1,explain:"kubectl rollout undo revient au ReplicaSet précédent. Avec --to-revision=N pour choisir une révision spécifique.",code:"kubectl rollout undo deploy/mon-app\nkubectl rollout history deploy/mon-app\nkubectl rollout undo deploy/mon-app --to-revision=2"},
    {type:'order',category:'Workloads',question:"Remets dans l'ordre les composants traversés lors d'un kubectl apply :",items:['kubectl CLI','kube-apiserver','Admission controllers','etcd','Controller Manager crée les Pods'],answer:[0,1,2,3,4],explain:"kubectl → API Server (auth + RBAC) → Admission controllers (validation/mutation) → etcd (persistance) → Controller Manager réagit et crée les ressources."},
    {type:'qcm',category:'Scheduling',question:"Quelle classe QoS un Pod obtient-il si requests == limits sur tous ses containers ?",options:['BestEffort','Burstable','Guaranteed','Premium'],answer:2,explain:"Guaranteed : requests == limits sur tous les containers → priorité maximale, évincé en dernier en cas de pression mémoire. C'est la classe recommandée pour les services critiques."},
    {type:'tf',category:'Réseau',question:"Un Ingress Controller est inclus par défaut dans toute installation Kubernetes.",answer:false,explain:"Faux ! L'objet Ingress seul ne fait rien. Il faut installer un Ingress Controller (nginx, traefik, HAProxy...) séparément pour que les règles Ingress soient effectivement appliquées."},
    {type:'qcm',category:'Stockage',question:"Quelle est la différence entre un PersistentVolume (PV) et un PersistentVolumeClaim (PVC) ?",options:['PV = pour les bases de données, PVC = pour les fichiers','PV = stockage provisionné dans le cluster, PVC = demande de stockage faite par un Pod',"Le PVC est créé par l'admin, le PV par le développeur","Ce sont des synonymes"],answer:1,explain:"PV = le stockage réel (NFS, EBS, disque local...). PVC = la demande d'un Pod (\"je veux 10 Gi en ReadWriteOnce\"). K8s effectue le binding PVC→PV automatiquement."},
    {type:'qcm',category:'Débogage',question:'Un Pod reste en état "Pending". Quelle est la cause la plus probable ?',options:["Le container crashe au démarrage","Aucun node n'a assez de ressources pour le scheduler","La liveness probe échoue","Le Secret n'existe pas"],answer:1,explain:"Pending = le scheduler n'a pas pu placer le Pod. Causes : ressources insuffisantes, node affinity trop restrictive, taints sans tolerations. kubectl describe pod → Events."},
    {type:'qcm',category:'Sécurité',question:"Que définit un Role RBAC dans Kubernetes ?",options:["Un utilisateur du cluster","Un ensemble de permissions sur des ressources dans UN namespace","Un ensemble de permissions à l'échelle du cluster","Un groupe de nodes"],answer:1,explain:"Role = permissions dans un namespace. ClusterRole = permissions à l'échelle du cluster. RoleBinding attache un Role à un utilisateur ou ServiceAccount dans un namespace.",code:'kind: Role\napiVersion: rbac.authorization.k8s.io/v1\nrules:\n- apiGroups: [""]\n  resources: ["pods"]\n  verbs: ["get","list","watch"]'},
    {type:'tf',category:'Workloads',question:"Un Init Container doit terminer avec succès (exit 0) avant que le container principal démarre.",answer:true,explain:"Vrai ! Les Init Containers s'exécutent séquentiellement avant les containers principaux. Si un Init Container échoue, K8s le relance selon la restartPolicy."},
    {type:'qcm',category:'Scheduling',question:"À quoi sert le pod anti-affinity ?",hint:'Pensez à la haute disponibilité.',options:["Empêcher un Pod de démarrer","Forcer deux Pods identiques à tourner sur des nodes différents","Limiter la consommation CPU","Associer un Pod à un node spécifique"],answer:1,explain:"Pod anti-affinity évite de co-localiser des Pods similaires. Ex. : les 3 replicas d'un service se répartissent sur 3 nodes différents → résistance aux pannes node."},
    {type:'qcm',category:'Commandes',question:"Quelle commande ouvre un shell dans un container en cours d'exécution ?",options:['kubectl run <pod> --sh','kubectl attach <pod>','kubectl exec -it <pod> -- /bin/sh','kubectl shell <pod>'],answer:2,explain:"kubectl exec -it <pod> -- /bin/sh ouvre un terminal interactif dans le container. Essentiel pour déboguer à chaud : vérifier fichiers, variables d'env, connectivité réseau.",code:"kubectl exec -it mon-pod -- /bin/sh\nkubectl exec -it mon-pod -c mon-container -- bash"},
    {type:'tf',category:'Réseau',question:"kube-proxy proxifie réellement le trafic réseau en espace utilisateur.",answer:false,explain:"Faux ! kube-proxy programme des règles iptables (ou ipvs) dans le kernel. Le trafic ne passe pas par kube-proxy lui-même — c'est le kernel qui route directement."},
    {type:'qcm',category:'Workloads',question:"Quelle ressource fait évoluer automatiquement le nombre de replicas selon l'usage CPU ?",options:['VerticalPodAutoscaler','HorizontalPodAutoscaler','ClusterAutoscaler','ReplicaController'],answer:1,explain:"HPA (HorizontalPodAutoscaler) adapte le nombre de Pods selon des métriques (CPU, RAM, custom). Nécessite Metrics Server et que les requests CPU soient définies.",code:"kubectl autoscale deploy mon-app \\\n  --min=2 --max=10 --cpu-percent=70"},
    {type:'qcm',category:'Débogage',question:'Qu\'indique un Pod en état "OOMKilled" ?',options:["Le Pod a dépassé sa limit CPU","Le Pod a dépassé sa limit mémoire","La liveness probe a échoué","Le node est tombé"],answer:1,explain:"OOMKilled = Out Of Memory Killed. Le container a dépassé sa limit mémoire et le kernel l'a tué. Solution : augmenter la limit memory, ou déboguer la fuite mémoire."},
    {type:'qcm',category:'Architecture',question:"Quel mécanisme K8s utilisent les composants pour être notifiés des changements en temps réel ?",options:["Polling toutes les secondes","Long-polling HTTP","Watch sur l'API Server","Webhook push"],answer:2,explain:"Tous les composants (kubelet, controller-manager...) utilisent le mécanisme watch de l'API Server : une connexion longue durée qui diffuse les événements dès qu'un objet change."},
  ],
  architect: [
    {type:'qcm',category:'Sécurité',question:"Un Pod doit lire des secrets AWS depuis Vault. Quelle est la bonne approche K8s native ?",hint:'Pensez au principe du moindre privilège.',options:["Mettre les credentials dans un ConfigMap","Utiliser un ServiceAccount + IRSA/Workload Identity + External Secrets Operator","Coder en dur les credentials dans l'image","Passer les credentials en arguments de container"],answer:1,explain:"Bonne pratique : ServiceAccount avec annotation cloud (IRSA sur AWS, Workload Identity sur GCP) + External Secrets Operator qui synchronise Vault/cloud secrets vers K8s Secrets."},
    {type:'tf',category:'Réseau',question:'Une NetworkPolicy "deny-all" ingress sur un namespace bloque aussi le trafic entre les Pods du même namespace.',answer:true,explain:"Vrai ! Une NetworkPolicy ingress sans podSelector ni namespaceSelector bloque tout trafic entrant, y compris intra-namespace. Il faut explicitement autoriser les Pods entre eux."},
    {type:'qcm',category:'Scheduling',question:"Quelle est la différence entre un Taint et une Toleration ?",options:["Taint = sur le Pod, Toleration = sur le Node","Taint = sur le Node (repousse), Toleration = sur le Pod (permet de tolérer)","Ce sont des synonymes","Taint = ressource, Toleration = contrainte"],answer:1,explain:"Taint sur un Node : \"ne place pas de Pods ici sauf s'ils tolèrent ce taint\". Toleration sur un Pod : \"j'accepte de tourner sur des nodes avec ce taint\". Ex. : nodes GPU réservés.",code:"# Taint sur un node GPU\nkubectl taint nodes gpu-node gpu=true:NoSchedule\n\n# Toleration dans le Pod spec\ntolerations:\n- key: \"gpu\"\n  value: \"true\"\n  effect: \"NoSchedule\""},
    {type:'qcm',category:'Sécurité',question:"Qu'est-ce qu'un Admission Webhook Mutating ?",hint:'Il intervient AVANT la persistance dans etcd.',options:["Un webhook qui supprime des ressources non conformes","Un webhook qui modifie les objets K8s avant leur persistance dans etcd","Un monitoring des accès à l'API Server","Un mécanisme de sauvegarde etcd"],answer:1,explain:"MutatingAdmissionWebhook intercepte les requêtes API et peut modifier les objets avant persistance. Ex. : injection automatique de sidecar Istio, ajout de labels, injection de PodSecurityContext."},
    {type:'order',category:'Débogage',question:"Mets dans l'ordre le diagnostic d'un service inaccessible :",items:["Vérifier les Endpoints du Service","Tester la résolution DNS","Vérifier les labels du Pod et le selector du Service","Vérifier les NetworkPolicies","Tester avec kubectl port-forward"],answer:[2,1,0,3,4],explain:"1) Labels Pod == selector Service ? 2) Le DNS résout-il ? 3) Des Endpoints existent-ils ? 4) Une NetworkPolicy bloque-t-elle ? 5) port-forward pour isoler le problème réseau."},
    {type:'qcm',category:'Architecture',question:"Dans un cluster HA, combien de replicas etcd faut-il pour tolérer 1 panne ?",options:['2','3','4','5'],answer:1,explain:"etcd utilise le consensus Raft. Pour tolérer N pannes, il faut 2N+1 membres. Pour 1 panne → 3 membres (quorum = 2). Pour 2 pannes → 5 membres."},
    {type:'tf',category:'Workloads',question:"Un PodDisruptionBudget (PDB) empêche K8s d'évincer trop de Pods simultanément lors d'une maintenance.",answer:true,explain:"Vrai ! PDB définit minAvailable ou maxUnavailable. Lors d'un drain de node, K8s respecte le PDB et attend que des Pods soient recréés avant d'en évincer d'autres.",code:"spec:\n  minAvailable: 2  # ou maxUnavailable: 1\n  selector:\n    matchLabels:\n      app: mon-service-critique"},
    {type:'qcm',category:'Réseau',question:"Qu'est-ce que le CNI (Container Network Interface) dans Kubernetes ?",options:["Le DNS interne du cluster","Un standard de plugin réseau qui configure la connectivité entre Pods","Le protocole entre kubelet et etcd","Le système d'authentification K8s"],answer:1,explain:"CNI est le standard de plugin réseau. Exemples : Calico (NetworkPolicies avancées), Cilium (eBPF, observabilité), Flannel (simple). Kubelet appelle le CNI pour configurer les interfaces réseau des Pods."},
    {type:'qcm',category:'Sécurité',question:"Quelle est la différence entre AuthN et AuthZ dans K8s ?",options:["Ce sont des synonymes","AuthN = vérifier l'identité (qui es-tu ?), AuthZ = vérifier les droits (qu'as-tu le droit de faire ?)","AuthN = pour les Pods, AuthZ = pour les utilisateurs","AuthN est géré par RBAC, AuthZ par les certificats"],answer:1,explain:"AuthN (Authentification) : qui es-tu ? Via certificats TLS, tokens, OIDC. AuthZ (Autorisation) : as-tu le droit ? Via RBAC. Ces deux étapes se déroulent dans l'API Server avant l'admission."},
    {type:'tf',category:'Architecture',question:"Kubernetes peut auto-réparer un cluster dont l'API Server est indisponible en utilisant kubelet directement.",answer:false,explain:"Faux ! Sans API Server, le cluster est \"gelé\". Les kubelet continuent de faire tourner les Pods existants, mais aucune nouvelle décision de scheduling ni réconciliation n'est possible."},
    {type:'qcm',category:'Performance',question:"Qu'est-ce que le Vertical Pod Autoscaler (VPA) ?",options:["Il ajoute des nodes au cluster","Il ajuste automatiquement les requests/limits CPU et RAM des Pods","Il adapte le nombre de Pods","Il migre les Pods vers des nodes plus puissants"],answer:1,explain:"VPA analyse l'usage réel des ressources et recommande (ou applique) des requests/limits optimales. Incompatible avec HPA sur la même métrique CPU/RAM."},
    {type:'qcm',category:'Architecture',question:"Qu'est-ce qu'un Operator Kubernetes ?",hint:'Pensez au Controller Manager, mais pour vos propres applications.',options:["Un administrateur humain du cluster","Un controller custom qui encode la connaissance opérationnelle d'une application dans K8s","Un type de Pod privilégié","Un plugin kubelet"],answer:1,explain:"Un Operator étend K8s avec des CRDs + controllers custom. Il automatise des tâches opérationnelles complexes (backup BDD, failover, scaling applicatif...). Ex. : Prometheus Operator, Postgres Operator."},
    {type:'tf',category:'Sécurité',question:"Les tokens ServiceAccount montés par défaut dans les Pods n'expirent jamais.",answer:false,explain:"Faux depuis K8s 1.21+ ! Les tokens ServiceAccount montés automatiquement (via TokenRequest API) ont une durée de vie limitée (défaut 1 h). Kubelet les renouvelle automatiquement."},
    {type:'qcm',category:'Débogage',question:"Un Deployment est bloqué en Rolling Update depuis 10 minutes. Quelle commande donne le statut ?",options:['kubectl get deploy mon-app','kubectl describe deploy mon-app','kubectl rollout status deploy/mon-app','kubectl logs deploy/mon-app'],answer:2,explain:"kubectl rollout status bloque et affiche en temps réel la progression. Si bloqué, c'est souvent une readiness probe qui échoue sur les nouveaux Pods.",code:"kubectl rollout status deploy/mon-app\nkubectl rollout history deploy/mon-app\n# Annuler si bloqué :\nkubectl rollout undo deploy/mon-app"},
    {type:'qcm',category:'Architecture',question:"Qu'est-ce qu'une CRD (Custom Resource Definition) ?",options:["Un type de Secret chiffré","Un moyen d'étendre l'API K8s avec ses propres types de ressources","Un plugin kubectl","Une règle de NetworkPolicy avancée"],answer:1,explain:"CRD permet de définir de nouveaux types de ressources K8s (ex. : MonApp, DatabaseCluster). Une fois créée, kubectl les reconnaît nativement. Combinée à un Operator, c'est la base de l'écosystème K8s."},
    {type:'qcm',category:'Scheduling',question:'Qu\'est-ce que la "Preemption" dans le scheduling K8s ?',options:["Le scheduler donne la priorité aux Pods récents","Le scheduler peut évincer des Pods basse priorité pour placer des Pods haute priorité","Un mécanisme de sauvegarde","L'autoscaling des nodes"],answer:1,explain:"Avec les PriorityClasses, K8s peut évincer des Pods basse priorité (Preemption) pour libérer de la place aux Pods haute priorité en attente. Configurable via PodPriorityClass.",code:"apiVersion: scheduling.k8s.io/v1\nkind: PriorityClass\nvalue: 1000000\npreemptionPolicy: PreemptLowerPriority"},
    {type:'tf',category:'Réseau',question:"Avec Cilium en mode eBPF, kube-proxy peut être complètement remplacé.",answer:true,explain:"Vrai ! Cilium en mode eBPF remplace kube-proxy et les règles iptables par des programmes eBPF dans le kernel, offrant de meilleures performances et une observabilité accrue."},
    {type:'qcm',category:'Architecture',question:'Quelle est la finalité d\'un "finalizer" sur une ressource K8s ?',options:["Empêcher la suppression définitive avant qu'une logique de nettoyage soit exécutée","Chiffrer la ressource avant le stockage dans etcd","Journaliser toutes les modifications","Valider le schéma YAML"],answer:0,explain:"Un finalizer bloque la suppression réelle d'une ressource jusqu'à ce qu'un controller le retire (après avoir exécuté le nettoyage). Ex. : supprimer un PVC force K8s à attendre la libération du volume."},
    {type:'qcm',category:'Performance',question:'Le Node Affinity "preferredDuringSchedulingIgnoredDuringExecution" signifie :',options:["Le Pod ne peut démarrer que sur ce node","Le scheduler préfère ce node mais peut en choisir un autre si nécessaire","L'affinité est appliquée même si le Pod tourne déjà","Le Pod est migré si le node ne satisfait plus la règle"],answer:1,explain:'"preferred" = contrainte souple, le scheduler fait de son mieux. "required" = contrainte stricte, le Pod ne démarre pas si aucun node ne correspond. "IgnoredDuringExecution" = pas de migration si le node change.'},
    {type:'qcm',category:'Sécurité',question:"Qu'est-ce que Pod Security Admission (remplaçant de PodSecurityPolicy depuis K8s 1.25) ?",options:["Un système de chiffrement des Pods","Un contrôleur qui applique des profils de sécurité (restricted/baseline/privileged) aux Pods d'un namespace","Un type de NetworkPolicy","Un mécanisme d'authentification multi-facteur"],answer:1,explain:"PSA applique 3 profils aux namespaces via des labels : privileged (aucune restriction), baseline (empêche les escalades de privilèges), restricted (meilleures pratiques strictes). Remplace les PodSecurityPolicies dépréciées.",code:"# Label sur le namespace\nkubectl label namespace mon-ns \\\n  pod-security.kubernetes.io/enforce=restricted"},
    {type:'tf',category:'Architecture',question:"Le kube-scheduler est un composant \"pluggable\" qu'on peut remplacer ou étendre avec un scheduler custom.",answer:true,explain:"Vrai ! K8s supporte les plugins du scheduling framework et les scheduler extenders. On peut écrire un scheduler custom ou utiliser des profils de scheduling multiples pour différents workloads."},
  ]
}
};
